// TCPA Compliance Check
// Business hours: Mon-Sat 8AM-7PM ET
// Check for STOP/opt-out keywords in recent history

const input = $input.first().json.body;
const errors = [];

// Validate required fields
if (!input.to) errors.push('Missing required field: to');
if (!input.message) errors.push('Missing required field: message');
if (!input.from) errors.push('Missing required field: from');

if (errors.length > 0) {
  return [{ json: { tcpa_pass: false, reason: errors.join('; '), error_type: 'validation' } }];
}

// Normalize phone to E.164
let phone = input.to.replace(/[^\d+]/g, '');
if (!phone.startsWith('+')) phone = '+1' + phone;
if (phone.length < 11) {
  return [{ json: { tcpa_pass: false, reason: 'Invalid phone number format', error_type: 'validation' } }];
}

// Check business hours in ET (America/New_York)
const now = new Date();
const etOptions = { timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric', weekday: 'long', hour12: false };
const etParts = new Intl.DateTimeFormat('en-US', etOptions).formatToParts(now);

const hour = parseInt(etParts.find(p => p.type === 'hour').value);
const minute = parseInt(etParts.find(p => p.type === 'minute').value);
const weekday = etParts.find(p => p.type === 'weekday').value;

const isSunday = weekday === 'Sunday';
const beforeHours = hour < 8;
const afterHours = hour >= 19;

if (isSunday) {
  return [{ json: { tcpa_pass: false, reason: 'TCPA: Cannot send SMS on Sundays', error_type: 'tcpa', current_time_et: `${weekday} ${hour}:${String(minute).padStart(2,'0')}` } }];
}

if (beforeHours || afterHours) {
  return [{ json: { tcpa_pass: false, reason: `TCPA: Outside business hours (Mon-Sat 8AM-7PM ET). Current: ${hour}:${String(minute).padStart(2,'0')} ET`, error_type: 'tcpa', current_time_et: `${weekday} ${hour}:${String(minute).padStart(2,'0')}` } }];
}

// Check for STOP words in the opt-out list (if provided)
const stopWords = ['stop', 'unsubscribe', 'cancel', 'quit', 'opt out', 'optout'];
const optedOut = input.opted_out !== false; // Block unless explicitly confirmed opted-in
if (optedOut) {
  return [{ json: { tcpa_pass: false, reason: 'TCPA: Recipient has opted out of SMS communications or opt-in not confirmed', error_type: 'tcpa' } }];
}

// TCPA passed
return [{
  json: {
    tcpa_pass: true,
    to: phone,
    from: input.from,
    message: input.message,
    checked_at: now.toISOString(),
    timezone_check: `${weekday} ${hour}:${String(minute).padStart(2,'0')} ET`
  }
}];
